var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 봤죠? 이번에는 저 혼자 해냈어요!","JPN":"リタお姉ちゃん！　見ました？　一人でやっつけたんですよ！","ENG":"Rita! Did you see that? I pulled it off all by myself this time!","TWN":"姐姐！看到了嗎？這次我自己做到了！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 말 안 듣고 제멋대로 굴더니 조금은 실력이 생겼네. 잘했어.","JPN":"そうだな。言うことも聞かずにいつも勝手に動き回ってたおかげで、少しは実力がついたんじゃないか。よくやった。","ENG":"Yeah, I saw. So you managed to improve a little, after being nothing but a troublemaker. That was good work back there.","TWN":"嗯。不聽話任性妄為，倒是練出了點實力。做得很好。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗! 방금 칭찬이었죠?!","JPN":"お！　今のは褒め言葉ですね！？","ENG":"Ooh! Was that a compliment just now?","TWN":"啊！剛剛那是稱讚吧？！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......아니. 나처럼 환청이라도 들었나 보지.","JPN":"……違う。私みたいに幻聴でも聞こえてるのか？","ENG":"No. Maybe you're hearing things. Just like me...","TWN":"……不是，你可能像我一樣出現幻聽了吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럴 리 없어요! 분명히 제 귀로 똑똑히 들었는걸요!","JPN":"そんなはずないです！　確かに聞こえましたよ？","ENG":"But that can't be! I could have sworn I heard you say it!","TWN":"不可能！我明明聽得清清楚楚！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"끈질기긴. 마음대로 생각해.","JPN":"しつこいな。勝手に言ってろ。","ENG":"You don't give up, do you? Think whatever you’d like.","TWN":"真煩，隨便你怎麼想。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 리타 언니! 같이 가요!","JPN":"あっ。リタお姉ちゃん！　置いていかないでくださいよ！","ENG":"Oh, Rita! Wait for me!","TWN":"啊！麗塔姐姐！一起走嘛！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으아......","JPN":"うわっ……","ENG":"Whoa...","TWN":"呃啊……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여기가 관제실이군. 걱정한 것보단 상태가 양호한데.","JPN":"ここが管制室か。予想していたより状態は良好だな。","ENG":"This must be the control room. It's in better shape than I thought.","TWN":"這裡就是控制室，狀態比想像的要好。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이렇게 망가졌는데도요?","JPN":"こんな壊れた状態なのに？","ENG":"But it's a wreck!","TWN":"都破成這樣了還好？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"밀거래를 하다 보면 알게 되지. 전쟁 전후에 생산된 기종들은 투박하긴 해도 그만큼 튼튼해.","JPN":"密売をしている人間にはわかるんだ。戦争前後に生産された機種は見た目はダサいが、その分頑丈だ。","ENG":"It's something you learn from dealing in the black market. Equipment made during the war was built to be as rugged as it looks.","TWN":"做過走私的都知道。戰爭前後生產的機種，雖然粗糙，但卻相當結實。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 정도로 보존되어 있다면 수리는 그렇게 어렵지 않아.","JPN":"この保存状態なら、修理はそう難しくないだろう。","ENG":"In this state, it should be good to go with a little repair.","TWN":"保存到這個程度，修理起來並不難。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, CRF가 거의 바닥났잖아요. 손으로 하려면 며칠 밤을 꼬박 새도 모자랄 거예요.","JPN":"でもリタお姉ちゃんはCRFがほぼ底をついているから、直接直すには数日徹夜しても終わらないんじゃ……","ENG":"But you're almost out of CRF, Rita. It'll take days to repair manually.","TWN":"姐姐，CRF已經沒剩下多少了。親自修理的話，幾天幾夜都不夠。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안심해, 꼬맹이.","JPN":"安心しろ、ガキ。","ENG":"Don't worry, kid.","TWN":"放心，小鬼。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"오메르타를 불러낼 수는 없지만...... 이런 작업을 할 만큼은 남겨 뒀어.","JPN":"オメルタは呼び出せないけど……これぐらいの作業ができる力は残しておいた。","ENG":"I may not be able to summon Omerta... but I saved up enough CRF for this sort of work.","TWN":"雖然沒法召喚奧梅爾塔……但做這些工作沒有問題。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말요?!","JPN":"本当ですか！？","ENG":"Really?!","TWN":"真的？！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 덕분에 꽤나 고생했지만 손 놓고 구경하는 일은 피한 셈이지.","JPN":"そう。おかげでかなり苦労はしたけど、指をくわえて見物するのだけは避けたかったからな。","ENG":"Yeah. It made the long walk suck that much more, but at least I won't have to just sit back and watch.","TWN":"嗯。雖然托你的福很辛苦，但也不能袖手旁觀。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};